function queryKnowledge(artistName) {
  const key = artistName.toLowerCase().trim();
  const result = { artist: artistName, found: false };
  
  // Exact match
  if (ARTIST_DB[key]) {
    result.found = true;
    result.profile = ARTIST_DB[key];
  } else {
    // Fuzzy match
    for (const [name, data] of Object.entries(ARTIST_DB)) {
      if (key.includes(name) || name.includes(key)) {
        result.found = true;
        result.profile = data;
        result.matchedAs = name;
        break;
      }
    }
  }
  
  // Check VIP watchlist
  const vipMatch = VIP_WATCHLIST.find(v => v.artist && (v.artist.toLowerCase().includes(key) || key.includes(v.artist?.toLowerCase())));
  if (vipMatch) {
    result.vipData = vipMatch;
    result.isVIP = true;
    result.vipTier = vipMatch.tier;
    // Include pricing evidence
    if (vipMatch.evidence) {
      result.historicalPricing = {};
      for (const [market, data] of Object.entries(vipMatch.evidence)) {
        result.historicalPricing[market] = {
          venue: data.venue,
          getIn: data.getIn,
          cap: data.cap,
          ticketsLeft: data.ticketsLeft,
          source: data.source
        };
      }
    }
    result.pattern = vipMatch.pattern;
    result.action = vipMatch.action;
  }
  
  // Check price history — return FULL snapshot if available
  for (const [recordKey, data] of Object.entries(PRICE_HISTORY)) {
    if (recordKey.toLowerCase().includes(key.split(' ')[0])) {
      result.priceHistory = { 
        snapshotDate: data.snapshotDate || data.date || data.recordedDate,
        tourDates: data.tourDates || data.shows || data.tour,
        pattern: data.pattern,
        keyInsight: data.keyInsight || data.keyInsights,
        priceRange: data.priceRange,
        background: data.background,
        metrics: data.metrics
      };
      break;
    }
  }
  
  // Find similar artists for comparison (same genre, similar tier)
  if (result.found && result.profile?.genre) {
    const genre = result.profile.genre.toLowerCase();
    result.similarArtists = [];
    for (const v of VIP_WATCHLIST) {
      if (!v.artist || v.artist.toLowerCase() === key) continue;
      if (v.genre && v.genre.toLowerCase().includes(genre.split('/')[0])) {
        result.similarArtists.push({ 
          artist: v.artist, tier: v.tier, 
          topPrice: v.evidence ? Math.max(...Object.values(v.evidence).map(e => e.getIn || 0)) : 0 
        });
      }
    }
    if (result.similarArtists.length === 0) delete result.similarArtists;
  }
  
  // Check breakout references for comparison
  const breakoutMatch = BREAKOUT_REFERENCES.find(b => b.name.toLowerCase().includes(key));
  if (breakoutMatch) {
    result.breakoutReference = breakoutMatch;
  }
  
  // Get performer ID
  const pid = PERFORMER_IDS[key];
  if (pid) result.performerId = pid;
  else if (pid === null) result.performerIdNote = "Known artist, no Vivid Seats ID yet";
  
  // Historical tour data
  const hist = HISTORICAL_DB[key];
  if (hist) {
    result.tourHistory = {
      totalUSShows: hist.shows,
      dateRange: hist.range,
      tourFrequency: hist.freq,
      venueScale: hist.scale,
      recentShows: hist.recent
    };
  }
  
  // Summary for the model
  if (result.found) {
    const parts = [];
    if (result.isVIP) parts.push(`⭐ VIP ${result.vipTier}-Tier confirmed seller`);
    if (result.profile?.genre) parts.push(`Genre: ${result.profile.genre}`);
    if (result.pattern) parts.push(`Pattern: ${result.pattern}`);
    if (result.priceHistory) parts.push(`Has historical price snapshot from ${result.priceHistory.snapshotDate}`);
    if (result.performerId) parts.push(`Vivid Seats ID: ${result.performerId}`);
    if (result.tourHistory) parts.push(`Tour history: ${result.tourHistory.totalUSShows} US shows (${result.tourHistory.dateRange}), ${result.tourHistory.tourFrequency}`);
    result.summary = parts.join(' | ');
  }
  
  return result;
}

function getVIPList() {
  return VIP_WATCHLIST.filter(v => v.artist).map(v => ({
    artist: v.artist,
    tier: v.tier,
    genre: v.genre,
    topPrice: v.evidence ? Math.max(...Object.values(v.evidence).map(e => e.getIn || e.price || 0)) : 0,
    pattern: v.pattern
  }));
}

function getBreakoutComparisons(spotifyListeners, venueCapacity) {
  return BREAKOUT_REFERENCES.map(ref => {
    const stages = ref.timeline || {};
    return {
      name: ref.name,
      genre: ref.genre,
      breakoutYear: ref.breakoutYear,
      trigger: ref.breakoutTrigger,
      preBreakoutListeners: stages.preBreakout?.monthlyListeners,
      preBreakoutVenues: stages.preBreakout?.venueSize,
      peakListeners: stages.peak?.monthlyListeners,
      peakVenues: stages.peak?.venueSize
    };
  });
}

